import React, { useCallback, useEffect, useState } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import useFetch from "../hooks/useFetch";
import Loader from "./utils/Loader";
import Tooltip from "./utils/Tooltip";

const Tasks = () => {
  const authState = useSelector((state) => state.authReducer);
  const [tasks, setTasks] = useState([]);
  const [fetchData, { loading }] = useFetch();

  const fetchTasks = useCallback(() => {
    const config = {
      url: "/tasks",
      method: "get",
      headers: {
        Authorization: `Bearer ${authState.token}`,
      },
    };

    fetchData(config, { showSuccessToast: false })
      .then((data) => {
        setTasks(data.tasks || []);
      })
      .catch((err) => console.error(err));
  }, [authState.token, fetchData]);

  useEffect(() => {
    if (!authState.isLoggedIn) return;
    fetchTasks();
  }, [authState.isLoggedIn, fetchTasks]);

  const handleDelete = (id) => {
    const config = {
      url: `/tasks/${id}`,
      method: "delete",
      headers: {
        Authorization: `Bearer ${authState.token}`,
      },
    };

    fetchData(config).then(() => fetchTasks());
  };

  return (
    <div className="my-2 mx-auto max-w-[700px] py-4">
      {tasks.length !== 0 && (
        <h2 className="my-2 text-xl">
          Your tasks ({tasks.length})
        </h2>
      )}

      {loading ? (
        <Loader />
      ) : tasks.length === 0 ? (
        <div className="flex items-center justify-center gap-4 h-[300px]">
          <span>No tasks found</span>
          <Link
            to="/tasks/add"
            className="bg-blue-500 text-white px-4 py-2 rounded-md"
          >
            + Add new task
          </Link>
        </div>
      ) : (
        tasks.map((task, index) => (
          <div
            key={task.id}
            className="bg-white my-4 p-4 rounded-md shadow-md"
          >
            <div className="flex items-center">
              <span className="font-medium">
                Task - {index + 1}
              </span>

              <Tooltip text="Edit this task" position="top">
                <Link
                  to={`/tasks/${task.id}`}
                  className="ml-auto mr-2 text-green-600"
                >
                  ✏️
                </Link>
              </Tooltip>

              <Tooltip text="Delete this task" position="top">
                <span
                  className="text-red-500 cursor-pointer"
                  onClick={() => handleDelete(task.id)}
                >
                  🗑️
                </span>
              </Tooltip>
            </div>

            {/* TITLE */}
            <div className="font-semibold mt-2 text-lg">
              Title: {task.title}
            </div>

            {/* STATUS */}
            <div className="text-sm mt-2">
              Status:{" "}
              <span
                className={
                  task.status === "Completed"
                    ? "text-green-600"
                    : task.status === "In Progress"
                    ? "text-yellow-600"
                    : "text-blue-600"
                }
              >
                {task.status}
              </span>
            </div>

            {/* DATE */}
            <div className="text-xs text-gray-400 mt-1">
              Created:{" "}
              {task.createdAt
                ? new Date(task.createdAt).toLocaleString()
                : "N/A"}
            </div>
          </div>
        ))
      )}
    </div>
  );
};

export default Tasks;
